import Link from "next/link";

import { Badge } from "@/components/ui/badge";
import { EmptyState } from "@/components/ui/empty-state";
import { formatCurrency, formatDate } from "@/lib/formatters";
import type { TradeRow } from "@/lib/types";
import { truncateText } from "@/lib/utils";

function DirectionBadge({ direction }: { direction: TradeRow["direction"] }) {
  return <Badge variant={direction === "long" ? "positive" : "negative"}>{direction}</Badge>;
}

function StatusBadge({ status }: { status: TradeRow["status"] }) {
  const variant =
    status === "open"
      ? "info"
      : status === "partial"
        ? "warning"
        : status === "cancelled"
          ? "default"
          : "negative";

  return <Badge variant={variant}>{status}</Badge>;
}

export function OpenPositionsTable({
  trades,
  compact = false,
  adminBasePath,
}: {
  trades: TradeRow[];
  compact?: boolean;
  adminBasePath?: string;
}) {
  if (trades.length === 0) {
    return (
      <EmptyState
        title="No open positions"
        description="Open trade ideas will appear here once they are logged by the admin."
      />
    );
  }

  const visibleTrades = compact ? trades.slice(0, 4) : trades;

  return (
    <>
      <div className="grid gap-4 md:hidden">
        {visibleTrades.map((trade) => (
          <div
            className="rounded-3xl border border-white/10 bg-white/5 p-5"
            key={trade.id}
          >
            <div className="flex items-start justify-between gap-4">
              <div>
                <p className="text-lg font-semibold text-foreground">{trade.ticker}</p>
                <p className="mt-1 text-sm text-muted-foreground">{trade.source_label}</p>
              </div>
              <DirectionBadge direction={trade.direction} />
            </div>
            <div className="mt-4 grid grid-cols-2 gap-3 text-sm">
              <div>
                <p className="text-muted-foreground">Entry</p>
                <p className="mt-1 text-foreground">{formatCurrency(trade.entry_price)}</p>
              </div>
              <div>
                <p className="text-muted-foreground">Stop</p>
                <p className="mt-1 text-foreground">{formatCurrency(trade.stop_price)}</p>
              </div>
              <div>
                <p className="text-muted-foreground">Target 1</p>
                <p className="mt-1 text-foreground">{formatCurrency(trade.target_1)}</p>
              </div>
              <div>
                <p className="text-muted-foreground">Opened</p>
                <p className="mt-1 text-foreground">{formatDate(trade.opened_at)}</p>
              </div>
            </div>
            <p className="mt-4 text-sm leading-6 text-muted-foreground">
              {truncateText(trade.notes, 140)}
            </p>
            <div className="mt-4 flex flex-wrap gap-2">
              <StatusBadge status={trade.status} />
              {adminBasePath ? (
                <>
                  <Link
                    className="text-sm font-medium text-sky-300 transition hover:text-sky-200"
                    href={`${adminBasePath}?edit=${trade.id}`}
                  >
                    Edit
                  </Link>
                  <Link
                    className="text-sm font-medium text-sky-300 transition hover:text-sky-200"
                    href={`${adminBasePath}?close=${trade.id}`}
                  >
                    Close
                  </Link>
                </>
              ) : null}
            </div>
          </div>
        ))}
      </div>
      <div className="hidden overflow-hidden rounded-3xl border border-white/10 md:block">
        <table className="min-w-full divide-y divide-white/10">
          <thead className="bg-white/5">
            <tr className="text-left text-xs uppercase tracking-[0.22em] text-muted-foreground">
              <th className="px-4 py-4">Ticker</th>
              <th className="px-4 py-4">Direction</th>
              <th className="px-4 py-4">Entry</th>
              <th className="px-4 py-4">Stop</th>
              <th className="px-4 py-4">Targets</th>
              <th className="px-4 py-4">Opened</th>
              <th className="px-4 py-4">Status</th>
              <th className="px-4 py-4">Source</th>
              <th className="px-4 py-4">Chart</th>
              <th className="px-4 py-4">Notes</th>
              {adminBasePath ? <th className="px-4 py-4">Actions</th> : null}
            </tr>
          </thead>
          <tbody className="divide-y divide-white/10 bg-white/[0.03] text-sm">
            {visibleTrades.map((trade) => (
              <tr className="align-top" key={trade.id}>
                <td className="px-4 py-4 font-semibold text-foreground">{trade.ticker}</td>
                <td className="px-4 py-4">
                  <DirectionBadge direction={trade.direction} />
                </td>
                <td className="px-4 py-4 text-foreground">{formatCurrency(trade.entry_price)}</td>
                <td className="px-4 py-4 text-foreground">{formatCurrency(trade.stop_price)}</td>
                <td className="px-4 py-4 text-muted-foreground">
                  <div>{formatCurrency(trade.target_1)}</div>
                  <div>{formatCurrency(trade.target_2)}</div>
                  <div>{formatCurrency(trade.target_3)}</div>
                </td>
                <td className="px-4 py-4 text-muted-foreground">{formatDate(trade.opened_at)}</td>
                <td className="px-4 py-4">
                  <StatusBadge status={trade.status} />
                </td>
                <td className="px-4 py-4 text-muted-foreground">{trade.source_label ?? "N/A"}</td>
                <td className="px-4 py-4">
                  {trade.chart_image_url ? (
                    <img
                      alt={`${trade.ticker} chart`}
                      className="h-14 w-20 rounded-2xl border border-white/10 object-cover"
                      src={trade.chart_image_url}
                    />
                  ) : (
                    <div className="flex h-14 w-20 items-center justify-center rounded-2xl border border-dashed border-white/10 text-xs text-muted-foreground">
                      No chart
                    </div>
                  )}
                </td>
                <td className="max-w-xs px-4 py-4 text-muted-foreground">
                  {truncateText(trade.notes, compact ? 80 : 160)}
                </td>
                {adminBasePath ? (
                  <td className="px-4 py-4">
                    <div className="flex flex-col gap-2">
                      <Link className="text-sky-300 transition hover:text-sky-200" href={`${adminBasePath}?edit=${trade.id}`}>
                        Edit
                      </Link>
                      <Link className="text-sky-300 transition hover:text-sky-200" href={`${adminBasePath}?close=${trade.id}`}>
                        Close
                      </Link>
                    </div>
                  </td>
                ) : null}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}
