import type { HTMLAttributes, PropsWithChildren } from "react";

import { cn } from "@/lib/utils";

type BadgeVariant = "default" | "positive" | "negative" | "warning" | "info";

export function Badge({
  children,
  variant = "default",
  className,
  ...props
}: PropsWithChildren<
  HTMLAttributes<HTMLSpanElement> & {
    variant?: BadgeVariant;
  }
>) {
  return (
    <span
      className={cn(
        "inline-flex items-center rounded-full border px-3 py-1 text-xs font-medium uppercase tracking-[0.2em]",
        variant === "default" && "border-white/10 bg-white/5 text-muted-foreground",
        variant === "positive" && "border-emerald-500/20 bg-emerald-500/10 text-emerald-300",
        variant === "negative" && "border-red-500/20 bg-red-500/10 text-red-300",
        variant === "warning" && "border-amber-500/20 bg-amber-500/10 text-amber-300",
        variant === "info" && "border-sky-500/20 bg-sky-500/10 text-sky-300",
        className,
      )}
      {...props}
    >
      {children}
    </span>
  );
}
