import Link from "next/link";
import { redirect } from "next/navigation";

import { CloseTradeForm } from "@/components/admin/close-trade-form";
import { EquitySnapshotForm } from "@/components/admin/equity-snapshot-form";
import { SettingsForm } from "@/components/admin/settings-form";
import { TradeForm } from "@/components/admin/trade-form";
import { OpenPositionsTable } from "@/components/trades/open-positions-table";
import { Badge } from "@/components/ui/badge";
import { buttonStyles } from "@/components/ui/button";
import { Card, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { formatCurrency, formatPercent, formatSignedNumber } from "@/lib/formatters";
import { getAdminModelData } from "@/lib/queries";
import { createServerSupabaseClient } from "@/lib/supabase/server";
import { isSupabaseConfigured } from "@/lib/utils";
import { logoutAction } from "@/lib/actions";

export const dynamic = "force-dynamic";

type PageProps = {
  searchParams: Promise<{
    edit?: string;
    close?: string;
    error?: string;
    saved?: string;
  }>;
};

export default async function AdminPage({ searchParams }: PageProps) {
  const params = await searchParams;
  const previewMode = !isSupabaseConfigured();

  if (!previewMode) {
    const supabase = await createServerSupabaseClient();
    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      redirect(`/login?next=${encodeURIComponent("/admin")}`);
    }
  }

  const data = await getAdminModelData({
    editTradeId: params.edit,
    closeTradeId: params.close,
  });

  return (
    <div className="space-y-8">
      <section className="rounded-[2rem] border border-white/10 bg-card/90 px-6 py-8 shadow-panel sm:px-8">
        <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
          <div>
            <Badge variant="info">Admin Console</Badge>
            <h1 className="font-heading mt-4 text-4xl font-semibold tracking-tight text-foreground">
              Portfolio operations
            </h1>
            <p className="mt-4 max-w-3xl text-base leading-7 text-muted-foreground">
              Log new trades, edit existing signals, close positions with long/short-aware math,
              and manage public model settings from one screen.
            </p>
          </div>
          {!previewMode ? (
            <form action={logoutAction}>
              <button className={buttonStyles({ variant: "secondary", size: "md" })} type="submit">
                Sign out
              </button>
            </form>
          ) : null}
        </div>
      </section>

      {previewMode ? (
        <Card className="border-amber-500/20 bg-amber-500/10">
          <p className="text-sm leading-7 text-amber-100">
            Preview mode is active. Configure Supabase to enable authenticated admin mutations and
            persistence.
          </p>
        </Card>
      ) : null}

      {params.error ? (
        <Card className="border-red-500/20 bg-red-500/10">
          <p className="text-sm text-red-200">{params.error}</p>
        </Card>
      ) : null}

      {params.saved ? (
        <Card className="border-emerald-500/20 bg-emerald-500/10">
          <p className="text-sm text-emerald-200">
            Saved {params.saved === "close" ? "trade close" : params.saved}.
          </p>
        </Card>
      ) : null}

      <section className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <Card>
          <p className="text-sm text-muted-foreground">Starting capital</p>
          <p className="mt-3 text-2xl font-semibold text-foreground">
            {formatCurrency(data.settings.starting_capital)}
          </p>
        </Card>
        <Card>
          <p className="text-sm text-muted-foreground">Current model equity</p>
          <p className="mt-3 text-2xl font-semibold text-foreground">
            {formatCurrency(data.stats.currentEquity)}
          </p>
        </Card>
        <Card>
          <p className="text-sm text-muted-foreground">Net return</p>
          <p className="mt-3 text-2xl font-semibold text-sky-300">
            {formatPercent(data.stats.totalReturnPct)}
          </p>
        </Card>
        <Card>
          <p className="text-sm text-muted-foreground">Average R</p>
          <p className="mt-3 text-2xl font-semibold text-foreground">
            {formatSignedNumber(data.stats.averageR)}
          </p>
        </Card>
      </section>

      <section className="grid gap-6 xl:grid-cols-[minmax(0,1.2fr)_minmax(360px,0.8fr)]">
        <SettingsForm disabled={previewMode} settings={data.settings} />
        <EquitySnapshotForm disabled={previewMode} />
      </section>

      <section className="grid gap-6 xl:grid-cols-[minmax(0,1.25fr)_minmax(360px,0.75fr)]">
        <TradeForm disabled={previewMode} trade={data.selectedTrade} />
        <CloseTradeForm disabled={previewMode} trade={data.closeTrade} />
      </section>

      <Card>
        <CardHeader>
          <div>
            <CardTitle>Manage open positions</CardTitle>
            <CardDescription>
              Select an open trade to edit its setup or close it with a final outcome.
            </CardDescription>
          </div>
          {(params.edit || params.close) && (
            <Link className={buttonStyles({ variant: "ghost", size: "sm" })} href="/admin">
              Clear selection
            </Link>
          )}
        </CardHeader>
        <OpenPositionsTable adminBasePath="/admin" trades={data.openTrades} />
      </Card>
    </div>
  );
}
